```class Solution {
public:
    int minDays(int n) {
        int days = 0;
        while (n > 0) {
            if (n % 2 == 0) {
                n /= 2;
            } else if (n % 3 == 0) {
                n /= 3;
            } else {
                n--;
            }
            days++;
        }
        return days;
    }
};
